SELECT * FROM friend_request
WHERE from_user_id = #{fromUserId}
  AND to_user_id = #{toUserId}
  AND status = 0
  AND deleted = 0

mapper.update:
UPDATE friend_request
SET status = #{status}, update_time = NOW()
WHERE id = #{id}

UPDATE friend_request
SET deleted = 1, update_time = NOW()
WHERE id = #{id}
